get.description:
The endpoint retrieves pending items for a specific resource.

The response of this request can be documented as a JSON schema:

``` json
{
    "type": "object",
    "properties": {
        "datos": {
            "type": "array",
            "items": {
                "type": "object",
                "properties": {
                    "codigo": {
                        "type": "integer"
                    },
                    "creado": {
                        "type": "integer"
                    },
                    "modificado": {
                        "type": "integer"
                    },
                    "modulo": {
                        "type": "string"
                    },
                    "accion": {
                        "type": "string"
                    },
                    "idProceso": {
                        "type": "integer"
                    },
                    "mensaje": {
                        "type": "string"
                    },
                    "link": {
                        "type": "object",
                        "properties": {
                            "url": {
                                "type": "string"
                            },
                            "tipo": {
                                "type": "string"
                            },
                            "metadata": {
                                "type": "object",
                                "properties": {
                                    "version": {
                                        "type": "string"
                                    },
                                    "timestamp": {
                                        "type": "integer"
                                    }
                                }
                            },
                            "rutaBase": {
                                "type": "string"
                            },
                            "parametros": {
                                "type": "object",
                                "properties": {
                                    "ver": {
                                        "type": "string"
                                    },
                                    "accion": {
                                        "type": "string"
                                    },
                                    "codigo": {
                                        "type": "integer"
                                    },
                                    "categoria": {
                                        "type": "string"
                                    }
                                }
                            }
                        }
                    }
                }
            }
        },
        "success": {
            "type": "boolean"
        },
        "cantidad": {
            "type": "integer"
        }
    }
}

 ```
